func (app *App) methodInt(s string) int {

	if len(app.configured.RequestMethods) == 0 {

		switch s {
		case MethodGet:
			return 0
		case MethodHead:
			return 1
		case MethodPost:
			return 2
		case MethodPut:
			return 3
		case MethodDelete:
			return 4
		case MethodConnect:
			return 5
		case MethodOptions:
			return 6
		case MethodTrace:
			return 7
		case MethodPatch:
			return 8
		default:
			return -1
		}
	}

	for i, v := range app.config.RequestMethods {
		if s == v {
			return i
		}
	}

	return -1
}
